// Extract source data from payload
const payload = $input.first().json.payload;

// Parse UTM parameters if present
const utmParams = {
  utm_source: payload.utm_source || null,
  utm_medium: payload.utm_medium || null,
  utm_campaign: payload.utm_campaign || null,
  utm_term: payload.utm_term || null,
  utm_content: payload.utm_content || null
};

// Determine lead source
let source = payload.source || 'direct';
let sourceDetail = null;

if (utmParams.utm_source) {
  source = utmParams.utm_source;
  sourceDetail = utmParams.utm_medium || utmParams.utm_campaign;
} else if (payload.referrer) {
  // Parse referrer to determine source
  const referrer = payload.referrer.toLowerCase();
  if (referrer.includes('google')) source = 'google';
  else if (referrer.includes('facebook')) source = 'facebook';
  else if (referrer.includes('linkedin')) source = 'linkedin';
  else if (referrer.includes('yelp')) source = 'yelp';
  else source = 'referral';
  sourceDetail = payload.referrer;
}

return {
  lead_id: $input.first().json.entity_id,
  agency_workspace_id: $input.first().json.agency_workspace_id,
  source: source,
  source_detail: sourceDetail,
  utm_params: utmParams,
  raw_payload: payload
};
